import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Heart, ListPlus, Trash2, Play, Pause, SkipForward, SkipBack, Trophy } from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const audioRef = useRef(null);
  
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

  // 1. Tải danh sách nhạc từ Server
  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) {
      console.error("Lỗi tải danh sách nhạc:", err);
    }
  };

  useEffect(() => {
    fetchSongs();
  }, []);

  // 2. Chức năng LIKE (Sửa lỗi 404 - Khớp với Backend /like/:id)
  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập để Like!");
    
    try {
      const response = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      
      // Cập nhật số lượt Like ngay trên giao diện mà không load lại trang
      setSongs(prevSongs => 
        prevSongs.map(s => s._id === songId ? response.data : s)
      );
    } catch (err) {
      console.error("Lỗi khi Like:", err);
      alert("Không thể thực hiện Like lúc này.");
    }
  };

  // 3. Chức năng Tạo Playlist mới
  const handleCreatePlaylist = async () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    
    const title = prompt("Nhập tên Playlist mới của bạn:");
    if (!title) return;

    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: title,
        userId: loggedInUser._id || loggedInUser.id,
        songIds: []
      });
      alert("Tạo Playlist thành công! Bạn có thể xem trong trang cá nhân.");
    } catch (err) {
      console.error("Lỗi tạo playlist:", err);
      alert("Lỗi khi tạo playlist.");
    }
  };

  // 4. Chức năng Admin Xóa bài
  const handleDelete = async (songId) => {
    if (!window.confirm("Bạn có chắc muốn xóa bài hát này?")) return;
    
    try {
      await axios.delete(`http://localhost:5000/api/songs/${songId}`, {
        data: { 
          userId: loggedInUser?._id || loggedInUser?.id, 
          role: loggedInUser?.role 
        }
      });
      setSongs(songs.filter(s => s._id !== songId));
      alert("Đã xóa bài hát!");
    } catch (err) { 
      console.error(err);
      alert("Bạn không có quyền xóa hoặc lỗi server."); 
    }
  };

  // 5. Điều khiển nhạc
  const playSong = (index) => {
    setCurrentIndex(index);
    setIsPlaying(true);
  };

  const nextSong = () => {
    if (songs.length > 0) {
      setCurrentIndex((currentIndex + 1) % songs.length);
    }
  };

  const prevSong = () => {
    if (songs.length > 0) {
      setCurrentIndex((currentIndex - 1 + songs.length) % songs.length);
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const formatTime = (time) => {
    if (isNaN(time)) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' : ''}${sec}`;
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '150px', color: '#333' }}>
      
      {/* Header & Ranking Button */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 style={{ fontWeight: 'bold', color: '#1db954' }}>P2TUNES - KHÁM PHÁ</h2>
        <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={handleCreatePlaylist} style={playlistBtnStyle}>
                <ListPlus size={18} /> Tạo Playlist
            </button>
            <button onClick={() => navigate('/ranking')} style={rankingBtnStyle}>
                <Trophy size={18} /> BXH
            </button>
        </div>
      </div>

      {/* Danh sách nhạc Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '25px', marginTop: '20px' }}>
        {songs.map((song, index) => (
          <div key={song._id} style={cardStyle}>
            <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '10px', backgroundColor: '#0a0a0aff' }}>
              <img 
                src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/200'} 
                style={{ width: '100%', height: '200px', objectFit: 'cover' }} 
                alt="cover" 
              />
              <button onClick={() => playSong(index)} style={hoverPlayBtn}>
                <Play fill="white" size={20} />
              </button>
              
              {/* Nút xóa cho ADMIN hoặc CHỦ BÀI VIẾT */}
              {(loggedInUser?.role === 'admin' || loggedInUser?._id === song.userId) && (
                <button onClick={() => handleDelete(song._id)} style={adminDeleteBtn}>
                  <Trash2 size={16} />
                </button>
              )}
            </div>

            <h4 style={{ margin: '15px 0 5px 0', fontSize: '16px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{song.title}</h4>
            <p style={{ fontSize: '14px', color: '#888', margin: '0' }}>{song.artist}</p>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px' }}>
               <div onClick={() => navigate(`/profile/${song.userId}`)} style={{ cursor: 'pointer', fontSize: '12px', color: '#1db954', fontWeight: 'bold' }}>
                 {song.uploaderName || "User"} 👤
               </div>
               
               <div style={{ display: 'flex', gap: '10px' }}>
                 <button onClick={() => handleLike(song._id)} style={actionBtn}>
                   <Heart 
                    size={18} 
                    color={song.likes?.includes(loggedInUser?._id || loggedInUser?.id) ? 'red' : '#888'} 
                    fill={song.likes?.includes(loggedInUser?._id || loggedInUser?.id) ? 'red' : 'none'} 
                   />
                   <span style={{ fontSize: '12px' }}>{song.likes?.length || 0}</span>
                 </button>
                 <button onClick={handleCreatePlaylist} style={actionBtn} title="Thêm vào playlist"><ListPlus size={18} /></button>
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* PLAYER NHẠC CỐ ĐỊNH PHÍA DƯỚI */}
      {currentSong && (
        <div style={playerContainerStyle}>
          <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
            <img 
                src={`http://localhost:5000${currentSong.imageUrl}`} 
                style={{ width: '55px', height: '55px', borderRadius: '5px', marginRight: '15px', objectFit: 'cover' }} 
                alt="" 
            />
            <div style={{ overflow: 'hidden' }}>
              <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{currentSong.title}</div>
              <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
              <SkipBack onClick={prevSong} style={{ cursor: 'pointer' }} />
              <button onClick={togglePlay} style={btnMain}>
                {isPlaying ? <Pause size={24} fill="black" /> : <Play size={24} fill="black" />}
              </button>
              <SkipForward onClick={nextSong} style={{ cursor: 'pointer' }} />
            </div>
            <div style={{ display: 'flex', alignItems: 'center', width: '100%', gap: '10px', marginTop: '5px' }}>
              <span style={{ fontSize: '11px' }}>{formatTime(currentTime)}</span>
              <input 
                type="range" 
                min="0" 
                max={duration || 0} 
                value={currentTime} 
                onChange={(e) => {
                    const time = e.target.value;
                    audioRef.current.currentTime = time;
                    setCurrentTime(time);
                }} 
                style={{ flex: 1, accentColor: '#1db954', cursor: 'pointer' }} 
              />
              <span style={{ fontSize: '11px' }}>{formatTime(duration)}</span>
            </div>
            <audio 
                ref={audioRef} 
                src={`http://localhost:5000${currentSong.songUrl}`} 
                onEnded={nextSong} 
                onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)} 
                onLoadedMetadata={() => setDuration(audioRef.current.duration)}
                autoPlay 
            />
          </div>
          <div style={{ width: '30%', textAlign: 'right', fontSize: '12px' }}>
            🔊 Volume Control
          </div>
        </div>
      )}
    </div>
  );
};

// CSS STYLES (Đã được làm đẹp thêm)
const cardStyle = { background: '#fff', padding: '15px', borderRadius: '15px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', transition: 'transform 0.2s' };
const hoverPlayBtn = { position: 'absolute', bottom: '10px', right: '10px', background: '#1db954', color: '#fff', border: 'none', width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 10px rgba(0,0,0,0.3)' };
const adminDeleteBtn = { position: 'absolute', top: '10px', right: '10px', background: 'rgba(255,0,0,0.8)', color: '#fff', border: 'none', width: '30px', height: '30px', borderRadius: '50%', cursor: 'pointer' };
const actionBtn = { background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '3px', color: '#888' };
const playerContainerStyle = { position: 'fixed', bottom: 0, left: 0, right: 0, background: '#181818', color: '#fff', padding: '10px 40px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 1000, boxShadow: '0 -5px 20px rgba(0,0,0,0.5)' };
const btnMain = { background: '#fff', border: 'none', width: '45px', height: '45px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const rankingBtnStyle = { display: 'flex', alignItems: 'center', gap: '5px', background: '#FFD700', border: 'none', padding: '8px 15px', borderRadius: '20px', cursor: 'pointer', fontWeight: 'bold' };
const playlistBtnStyle = { display: 'flex', alignItems: 'center', gap: '5px', background: '#f4f4f4', border: 'none', padding: '8px 15px', borderRadius: '20px', cursor: 'pointer', fontWeight: 'bold' };

export default Home;
